do {
  if (i%2 == 0) {
    if (i < n) request R_i;
    if (i < n) request R_{i+1};
  } else {
    if (i < n) request R_{i-1};
    if (i < n) request R_i;
  }
} while (1);
In which of the following situations is a deadlock possible?
A. n=40, k=26
B. n=21, k=12
C. n=20, k=10
D. n=41, k=19

